// ===== INPUT =====
const zodiacsList = $('Edit Fields').first().json.zodiacs;
const allCards = $('list_card').all().map(item => ({
  cardName: item.json['CardName'],
  url: item.json['ImageURL']
}));

// ===== KHO DỮ LIỆU ĐA DẠNG THEO BỘ BÀI =====
const suitData = {
  "Wands": {
    colors: ["đỏ rực", "cam đào", "vàng chanh", "đỏ tía", "vàng đồng"],
    objects: ["bật lửa", "nến thơm", "kính râm", "giày thể thao", "mũ lưỡi trai", "bình giữ nhiệt", "đèn pin mini", "áo khoác da", "vòng tay chỉ đỏ", "móc khóa kim loại"],
    locations: ["phòng gym", "sân vận động", "khu cắm trại", "phố đi bộ", "quán pub", "nhà hàng BBQ", "sân thượng lộng gió", "khu vui chơi giải trí", "bể bơi ngoài trời", "đỉnh núi"]
  },
  "Pentacles": {
    colors: ["nâu đất", "xanh lục", "xanh rêu", "xám ngọc trai", "đen huyền bí"],
    objects: ["ví da", "đồng hồ đeo tay", "sổ planner", "chậu cây mini", "đồng xu may mắn", "hộp đựng namecard", "cốc sứ", "nhẫn bạc", "túi vải canvas", "kẹp sách gỗ"],
    locations: ["nhà sách", "quán cà phê yên tĩnh", "công viên", "vườn bách thảo", "siêu thị", "ngân hàng", "tiệm bánh ngọt", "vườn hoa", "cửa hàng đồ cổ", "nhà hàng chay"]
  },
  "Swords": {
    colors: ["xanh lam", "trắng tinh khôi", "bạc lấp lánh", "xanh ngọc", "vàng nhạt"],
    objects: ["tai nghe", "cuốn sách yêu thích", "điện thoại di động", "bút bi", "kính viễn cận", "máy tính bảng", "sổ tay nhỏ", "gương mini", "nước hoa", "chiếc ô nhỏ"],
    locations: ["thư viện", "rạp chiếu phim", "studio nghệ thuật", "quán nhạc acoustic", "bảo tàng", "phòng triển lãm", "quán cà phê sách", "trung tâm thương mại", "cửa hàng tiện ích", "sân bay hoặc bến xe"]
  },
  "Cups": {
    colors: ["xanh nước biển", "tím mộng mơ", "hồng pastel", "xanh mòng két", "trắng ngà"],
    objects: ["bình nước thủy tinh", "vòng tay phong thủy", "đá thanh tẩy", "bùa bình an", "mặt dây chuyền", "cốc trà", "chiếc khăn tay", "kem dưỡng da", "gối tựa cổ", "khăn choàng mềm"],
    locations: ["bờ sông", "ven hồ", "hồ bơi", "quán trà đạo", "ngôi chùa thanh tịnh", "phòng tập yoga", "nhà hàng hải sản", "spa thư giãn", "bờ biển", "cửa hàng lưu niệm"]
  }
};

// Tổng hợp kho Major Arcana (Gộp tất cả lại cho các lá Ẩn Chính)
const majorData = {
  colors: [],
  objects: [],
  locations: []
};
for (const suit of Object.values(suitData)) {
  majorData.colors.push(...suit.colors);
  majorData.objects.push(...suit.objects);
  majorData.locations.push(...suit.locations);
}
suitData["Major"] = majorData;

// ===== SHUFFLE =====
function shuffleArray(array) {
  const shuffled = [...array];
  for (let i = shuffled.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
  }
  return shuffled;
}

const shuffledCards = shuffleArray(allCards);

// Trộn dữ liệu cho mỗi bộ bài và set index = 0
for (const data of Object.values(suitData)) {
  data.shuffledColors = shuffleArray(data.colors);
  data.shuffledObjects = shuffleArray(data.objects);
  data.shuffledLocations = shuffleArray(data.locations);
  data.usedColorIndex = 0;
  data.usedObjectIndex = 0;
  data.usedLocationIndex = 0;
}

const scheduleData = $('Schedule Trigger').first().json;
const scheduleDate = scheduleData.timestamp ? scheduleData.timestamp.split("T")[0] : new Date().toISOString().split("T")[0];

// HÀM LẤY NHÓM BÀI DỰA VÀO TÊN LÁ BÀI
function getSuitFromCardName(cardName) {
  const lowerName = cardName.toLowerCase();
  if (lowerName.includes("wand")) return "Wands";
  if (lowerName.includes("cup")) return "Cups";
  if (lowerName.includes("sword")) return "Swords";
  if (lowerName.includes("pentacle") || lowerName.includes("coin")) return "Pentacles";
  return "Major";
}

// GHÉP CUNG VÀ GÁN ITEMS TỪ LÁ BÀI
return zodiacsList.map((zodiac, index) => {
  const card = shuffledCards[index];
  const suit = getSuitFromCardName(card.cardName);
  const sData = suitData[suit];

  // Lấy vòng lặp % để không bao giờ bị lỗi undefined nếu 1 bộ xuất hiện quá nhiều lần
  const obj1 = sData.shuffledObjects[(sData.usedObjectIndex++) % sData.shuffledObjects.length];
  const obj2 = sData.shuffledObjects[(sData.usedObjectIndex++) % sData.shuffledObjects.length];
  const obj3 = sData.shuffledObjects[(sData.usedObjectIndex++) % sData.shuffledObjects.length];
  const luckyObjects = [obj1, obj2, obj3].join(", ");

  const loc1 = sData.shuffledLocations[(sData.usedLocationIndex++) % sData.shuffledLocations.length];
  const loc2 = sData.shuffledLocations[(sData.usedLocationIndex++) % sData.shuffledLocations.length];
  const loc3 = sData.shuffledLocations[(sData.usedLocationIndex++) % sData.shuffledLocations.length];
  const luckyLocations = [loc1, loc2, loc3].join(", ");

  const luckyColor = sData.shuffledColors[(sData.usedColorIndex++) % sData.shuffledColors.length];

  return {
    json: {
      zodiacSign: zodiac,
      cardName: card.cardName,
      url: card.url,
      date: scheduleDate,
      luckyColor: luckyColor,
      luckyObjects: luckyObjects,
      luckyLocations: luckyLocations,
      cardSuit: suit
    }
  };
});

const mySystemPrompt = "Bạn là một chuyên gia Tarot dày dặn kinh nghiệm. Nhiệm vụ của bạn là giải bài hàng ngày cho các cung hoàng đạo bằng tiếng Việt.";
const myUserPrompt = `📅 Ngày: ${$json.date}
♈ Cung hoàng đạo: ${$json.zodiacSign}
🎴 Lá bài Tarot: ${$json.cardName}

Hãy tạo lời giải Tarot theo cấu trúc JSON sau (KHÔNG thêm \`\`\`json hay bất kỳ markdown nào):

{
  "keyword": "3-5 từ khóa ngắn gọn, cách nhau bởi dấu phẩy",
  "love": "Phân tích chi tiết về tình yêu, hẹn hò, quan hệ. Đưa ra dự báo cụ thể và lời khuyên thiết thực. 100-150 từ.",
  "job": "Phân tích về công việc, sự nghiệp, cơ hội thăng tiến, thách thức. Gợi ý hành động cụ thể. 100-150 từ.",
  "finance": "Phân tích về tài chính, đầu tư, thu nhập, chi tiêu. Lời khuyên về quản lý tiền bạc. 100-150 từ.",
  "advice": "Lời khuyên tổng quan cho cả ngày: nên làm gì, tránh làm gì, thái độ nên có. 80-120 từ."
}

LƯU Ý QUAN TRỌNG:
- Viết hoàn toàn bằng tiếng Việt
- Trả về CHÍNH XÁC format JSON như trên, không thêm gì khác
- Không dùng markdown code blocks (\`\`\`json)
- Nội dung phải phù hợp với ý nghĩa thực tế của lá bài ${$json.cardName}
- Liên kết ý nghĩa với cung hoàng đạo và ngày hiện tại được cung cấp trong nội dung
- Giọng văn thân thiện, dễ hiểu, không quá huyền bí`;

return {
  json: {
    ...$json,
    bodyPayload: {
      model: "n8n2",
      messages: [
        { role: "system", content: mySystemPrompt },
        { role: "user", content: myUserPrompt }
      ],
      temperature: 0.7
    }
  }
};

let rawText = $input.first().json?.choices?.[0]?.message?.content || "";
const previousData = $('Loop Over Items').item.json;

// Hàm bóc tách JSON an toàn
function extractJSON(str) {
  if (typeof str === 'object') return str;
  if (!str) return {};

  let jsonStr = str.trim();
  if (jsonStr.includes('```')) {
    const match = jsonStr.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
    if (match && match[1]) {
      jsonStr = match[1].trim();
    } else {
      jsonStr = jsonStr.replace(/```(?:json)?/gi, '').replace(/```/g, '').trim();
    }
  }

  const startIndex = jsonStr.indexOf('{');
  const endIndex = jsonStr.lastIndexOf('}');
  if (startIndex !== -1 && endIndex !== -1 && endIndex > startIndex) {
    jsonStr = jsonStr.substring(startIndex, endIndex + 1);
  }

  try {
    return JSON.parse(jsonStr);
  } catch (e) {
    return {
      keyword: "Lỗi JSON",
      love: "Đã xảy ra lỗi khi tạo nội dung. Vui lòng thử lại.",
      job: "",
      finance: "",
      advice: ""
    };
  }
}

const aiResponse = extractJSON(rawText);

// Ghép kết quả phân tích của AI với Dữ liệu bốc ngẫu nhiên
return {
  json: {
    date: previousData.date,
    zodiacSign: previousData.zodiacSign,
    cardName: previousData.cardName,
    url: previousData.url,
    color: previousData.luckyColor,
    objects: previousData.luckyObjects,
    locations: previousData.luckyLocations,
    ...aiResponse
  }
};

const allZodiacs = $('Code in JavaScript').all().map(i => i.json);
if (!allZodiacs.length) return [];
const dateStr = allZodiacs[0].date;

const parts = dateStr.split("-");
const displayDate = parts.length === 3 ? `${parts[2]}/${parts[1]}/${parts[0]}` : dateStr;

// Tính Unix Timestamp cho 7:00 sáng cùng ngày (Múi giờ VN: UTC+7)
const publishDate = new Date(`${dateStr}T07:00:00+07:00`);
const scheduleUnix = Math.floor(publishDate.getTime() / 1000);
const nowUnix = Math.floor(Date.now() / 1000);

// FB yêu cầu scheduled_publish_time phải lớn hơn hiện tại ít nhất 10 phút (600 giây)
let isScheduled = true;
if (nowUnix + 600 >= scheduleUnix) {
  isScheduled = false; // Đã quá 6h50 sáng, đăng ngay lập tức!
}

// Cấu hình mã UTM để tracking GA4
const utmUrl = `https://phogotarot.com/zodiac-daily?utm_source=facebook&utm_medium=social_auto&utm_campaign=zodiac_daily&utm_content=${dateStr}`;
const hashtags = "#tarot #zodiac #12cunghoangdao #tarotdaily #phogotarot #cunghoangdao";

const templates = [
  {
    header: `🔮 THÔNG ĐIỆP TAROT HÀNG NGÀY (${displayDate}) 🔮\nVũ trụ gửi gắm điều gì đến 12 chòm sao hôm nay? Cùng điểm qua thẻ bài đại diện, màu sắc, đồ vật và địa điểm may mắn nhé:\n\n`,
    footer: `✨ Trải bài chi tiết về Tình Yêu, Công việc & Tài Chính đã có trên web!\n👉 Đọc luận giải đầy đủ nhất tại link bên dưới: ${utmUrl}\n\n${hashtags}`
  },
  {
    header: `✨ NĂNG LƯỢNG TAROT NGÀY ${displayDate} ✨\nHé lộ thông điệp từ các lá bài Tarot cho 12 cung hoàng đạo. Ai sẽ bùng nổ năng lượng hôm nay?\n\n`,
    footer: `👉 Khám phá ngay dự báo Tình cảm và Sự nghiệp của bạn tại link bên dưới: ${utmUrl}\n\n${hashtags}`
  },
  {
    header: `🌟 TRẢI BÀI TAROT 12 CUNG HOÀNG ĐẠO (${displayDate}) 🌟\nSắp xếp hành trang ngày mới cùng những gợi ý may mắn từ vũ trụ:\n\n`,
    footer: `🔮 Xem ngay lời khuyên tổng quan chi tiết tại link bên dưới: ${utmUrl}\n\n${hashtags}`
  },
  {
    header: `🌙 LỜI THÌ THẦM TỪ VŨ TRỤ (${displayDate}) 🌙\nMỗi lá bài Tarot là một thông điệp ẩn giấu. Cùng xem vũ trụ muốn nói gì với 12 chòm sao ngày hôm nay:\n\n`,
    footer: `💌 Đừng bỏ lỡ những dự báo bất ngờ về Tình yêu và Tiền bạc. Xem chi tiết tại link bên dưới: ${utmUrl}\n\n${hashtags}`
  },
  {
    header: `🔥 BẢN ĐỒ SAO & TAROT (${displayDate}) 🔥\nChuẩn bị tinh thần đón nhận một ngày đầy năng lượng với những lá bài đại diện và vận may của 12 cung hoàng đạo:\n\n`,
    footer: `📌 Xem luận giải sâu hơn cho cung của bạn tại link bên dưới: ${utmUrl}\n\n${hashtags}`
  }
];

const tpl = templates[Math.floor(Math.random() * templates.length)];

const zodiacIcons = {
  "Bạch Dương": "♈", "Kim Ngưu": "♉", "Song Tử": "♊", "Cự Giải": "♋", 
  "Sư Tử": "♌", "Xử Nữ": "♍", "Thiên Bình": "♎", "Bọ Cạp": "♏", 
  "Nhân Mã": "♐", "Ma Kết": "♑", "Bảo Bình": "♒", "Song Ngư": "♓"
};

let body = "";
allZodiacs.forEach(item => {
  const icon = zodiacIcons[item.zodiacSign] || "⭐";
  body += `${icon} ${item.zodiacSign.toUpperCase()}: ${item.cardName}\n`;
  body += `   🎨 Màu may mắn: ${item.luckyColor}\n`;
  body += `   🎁 Vật may mắn: ${item.luckyObjects}\n`;
  body += `   📍 Địa điểm: ${item.luckyLocations}\n\n`; // Dòng trống để cách biệt giữa các cung
});

const finalPost = tpl.header + body + tpl.footer;

// Xây dựng gói tin Payload cho API của Facebook
const fbPayload = {
  message: finalPost,
  link: utmUrl,
  access_token: "ĐIỀN_TOKEN_VĨNH_VIỄN_CỦA_BẠN_VÀO_ĐÂY"
};

if (isScheduled) {
  fbPayload.published = false;
  fbPayload.scheduled_publish_time = scheduleUnix;
} else {
  fbPayload.published = true;
}

return {
  json: {
    fbPayload: fbPayload
  }
};
